import mysql.connector

def import_data_with_load_data_infile(db_config, table_name, file_path, fields_terminated_by=',', lines_terminated_by='\n', enclosed_by='"', optionally_enclosed_by=False, ignore_lines=0):
    try:
        conn = mysql.connector.connect(**db_config)
        cursor = conn.cursor()

        # Enable LOCAL_INFILE for the session
        cursor.execute("SET GLOBAL local_infile = 1;")
        cursor.execute("SET SESSION local_infile = 1;")

        # Build the LOAD DATA INFILE statement
        load_data_sql = f"LOAD DATA LOCAL INFILE '{file_path}' " \
                        f"INTO TABLE {table_name} " \
                        f"FIELDS TERMINATED BY '{fields_terminated_by}' "
        
        if optionally_enclosed_by:
            load_data_sql += f"OPTIONALLY ENCLOSED BY '{enclosed_by}' "
        else:
            load_data_sql += f"ENCLOSED BY '{enclosed_by}' "

        load_data_sql += f"LINES TERMINATED BY '{lines_terminated_by}' "
        
        if ignore_lines > 0:
            load_data_sql += f"IGNORE {ignore_lines} LINES"

        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        conn.commit()
        print(f"Successfully loaded data from '{file_path}' into table '{table_name}'.")
        print(f"Rows affected: {cursor.rowcount}")

    except mysql.connector.Error as err:
        print(f"Error: {err}")
        if 'local_infile' in str(err) and 'disabled' in str(err):
            print("Please ensure 'local_infile = ON' is set in your MySQL server configuration (my.cnf or my.ini) and the MySQL server is restarted.")
            print("You might also need to ensure your MySQL user has FILE privilege.")
    finally:
        if 'conn' in locals() and conn.is_connected():
            cursor.close()
            conn.close()

